#[test]
fn groupref_invalid_is_error() {
    assert!(parse_pattern("a\\1", 0).is_err());
    assert!(parse_pattern("\\10", 0).is_err());
}

#[test]
fn groupref_exists() {
    assert_eq!(
        parsed("(a)(?(1)b|c)").data,
        vec![
            OpCode::Subpattern {
                group: Some(1),
                add_flags: 0,
                del_flags: 0,
                p: SubPattern {
                    data: vec![lit(97)]
                },
            },
            OpCode::GroupRefExists {
                cond_group: 1,
                yes: SubPattern {
                    data: vec![lit(98)]
                },
                no: Some(SubPattern {
                    data: vec![lit(99)]
                }),
            },
        ]
    );
}

