fn parse_err(pattern: &str) -> ParseError {
    parse_pattern(pattern, 0).expect_err("expected parse error")
}

#[test]
fn parse_error_display_includes_position() {
    let err = parse_err("(");
    let s = format!("{}", err);
    assert!(s.contains("at position"), "{}", s);
}

#[test]
fn err_bad_escape_at_end_of_pattern() {
    let err = parse_err(r"abc\");
    assert!(err.msg.contains("bad escape"), "{}", err.msg);
}

